import { Routes } from '@angular/router';

export const routes: Routes = [
  {
    path: 'auth',
    // Usamos 'login' porque tu archivo se llama login.ts y la clase Login
    loadComponent: () => import('./features/auth/login/login').then(m => m.Login)
  },
  {
    path: '',
    redirectTo: 'auth',
    pathMatch: 'full'
  },
  {
    path: '**',
    redirectTo: 'auth'
  }
];
